import React, { useState } from "react";
import "./Testimonials.css";
import TestimonialCard from "./TestimonialCard";

const Testimonials = () => {
  const [currentIndex, setCurrentIndex] = useState(0);

  const totalCards = 3; // Update this if you add more testimonials

  const nextCard = () => {
    setCurrentIndex((prev) => (prev + 1) % totalCards);
  };

  const prevCard = () => {
    setCurrentIndex((prev) => (prev - 1 + totalCards) % totalCards);
  };

  return (
    <div className="testimonials-section">
      <div className="title-box">
        <h1 className="title">Testimonials</h1>
        <p className="text">Hear what my colleagues have to say</p>
      </div>

      <div className="testimonials-overlay">
        <button className="scroll-btn left" onClick={prevCard}>
          &#8249;
        </button>

        <div className="carousel">
          {[0, 1, 2].map((i) => (
            <div
              key={i}
              className={`carousel-item ${
                i === currentIndex
                  ? "active"
                  : i === (currentIndex - 1 + totalCards) % totalCards
                  ? "prev"
                  : i === (currentIndex + 1) % totalCards
                  ? "next"
                  : "hidden"
              }`}
            >
              <TestimonialCard index={i} />
            </div>
          ))}
        </div>

        <button className="scroll-btn right" onClick={nextCard}>
          &#8250;
        </button>
      </div>
    </div>
  );
};

export default Testimonials;
